mapper.select:
SELECT COALESCE(MAX(game_no), 0) + 1
FROM assignment_champion_history
WHERE assignment_group_id = #{assignmentGroupId}

SELECT DISTINCT champion_id
FROM assignment_champion_history
WHERE assignment_group_id = #{assignmentGroupId}
AND game_no IN (
SELECT DISTINCT game_no
FROM assignment_champion_history
WHERE assignment_group_id = #{assignmentGroupId}
ORDER BY game_no DESC
LIMIT #{recentGameCount}
)

mapper.delete:
DELETE FROM assignment_champion_history
WHERE assignment_group_id = #{assignmentGroupId}
AND game_no NOT IN (
SELECT game_no
FROM (
SELECT DISTINCT game_no
FROM assignment_champion_history
WHERE assignment_group_id = #{assignmentGroupId}
ORDER BY game_no DESC
LIMIT #{keepGameCount}
) recent_games
)
